/* Tabbed form CSS */

.customtab {
    float: left;
}
.customtab tr {
        float:left;
}
.customtab label {
        background: #eee;
        padding: 7px 10px;
        border: 1px solid #ccc;
        margin-left: -1px;
        position: relative;
        left: 1px;
        border-radius:5px 5px 0px 0px;
        cursor:pointer;
        border-bottom:none;
        text-align:center;
font-size: 14px;
font-family :arial;
}
.customtab [type=radio] {
        display: none;
}
[type=radio]:checked ~ label {
    background:white;
    border-bottom: 1px solid white;
    z-index: 2;
}

