/* Radio button to Tab Start*/
.cssriskrate .nx-radio-group {
    justify-content: left;
    row-gap: 0px;
    margin-left: 10px !important;

}

/* Make each option act like a block */
.cssriskrate .nx-radio {
    margin: -10px;

}
/* Base styling for the clickable label container */
.cssriskrate .nx-radio-container {
    min-width: 140px !important;
    /* padding: 6px 5px; */
    padding-top: 6px;
    padding-left: 0px !important;
    text-align: center;
    font-weight: bold;
    font-style: italic;
    border-radius: 2px;
    height: 30px !important;
}


/* Hide the default radio circle */
.cssriskrate .nx-radio-faux {
    display: none;
    visibility: hidden;
    margin-left: -10px;
}

/* Ensure label text is centered */
.cssriskrate .nx-radio-label {
    display: block;
    width: 100%;
}

/* LOW */
.cssriskrate input[value="CHANGE"] + .nx-radio-container {
    background-color: rgb(215, 219, 211);
    color: #000;

}

/* SIGNIFICANT */
.cssriskrate input[value="OUTAGE"] + .nx-radio-container {
    background-color: rgb(215, 219, 211);
    color: #000;
}



/* Optional: visual feedback when selected */
.cssriskrate input:checked + .nx-radio-container {
    outline: 1px solid #333;
    background-color: white !important;
}

/* EXTREME – force white text */
.cssriskrate input[value="EXTREME"] + .nx-radio-container  {
    color: rgb(255, 255, 255) !important;
   background-color: black!important;

}
/* EXTREME – force white text */
.cssriskrate input[value="EXTREME"] + .nx-radio-container .nx-radio-label {
    color: #fff !important;
}
